<?php include __DIR__.'/includes/header.php';$rows=db()->query("SELECT * FROM opportunities WHERE active=1 ORDER BY id DESC")->fetchAll();?><section class="section"><h1>Opportunities</h1><div class="grid"><?php if(!$rows): ?><div class="card"><h3>Opportunities coming soon</h3></div><?php endif; ?><?php foreach($rows as $r): ?><div class="card"><span class="badge"><?=h($r['opportunity_type'])?></span><h3><?=h($r['title'])?></h3><p><?=h($r['description'])?></p></div><?php endforeach; ?></div></section><?php include __DIR__.'/includes/footer.php'; ?>